<div class="sw-hud">
    <!-- ID và data-color để JS xử lý -->
    <div class="sw-c" id="hud-container" data-color="$6 $4">
        <div class="sw-f sw-h">
            <!-- $1 $2: Cho phép xuống dòng -->
            <span id="hud-1-2">$1 - $2</span>
            <!-- $3: Giữ nguyên -->
            <span class="sw-w" id="hud-3">$3</span>
        </div>
        <div class="sw-f">
            <!-- $4: JS sẽ tự điền biến Thời gian vào đây -->
            <div class="sw-t" id="hud-time">$4</div>
            <div class="sw-i">
                <!-- $5: JS sẽ tự điền biến Địa điểm vào đây -->
                <div class="sw-r"><span id="hud-loc">$5</span><span class="il"></span></div>
                <!-- $6: Giữ nguyên Thời tiết -->
                <div class="sw-r"><span id="hud-6">$6</span><span class="iw"></span></div>
            </div>
        </div>
    </div>
</div>

<script type="module">
    // Hàm lấy biến từ hệ thống (Risu/SillyTavern)
    const getStat = (path, def) => {
        try {
            if (typeof getAllVariables === 'function') {
                const all = getAllVariables();
                let val = _.get(all, 'stat_data.' + path);
                if (val !== undefined) return val;
                val = _.get(all, path);
                return val !== undefined ? val : def;
            }
            return def;
        } catch (e) { return def; }
    }

    async function initHUD() {
        if (typeof waitGlobalInitialized === 'function') await waitGlobalInitialized('Mvu');

        const render = () => {
            // 1. LẤY BIẾN
            const timeVal = getStat('Thế giới.Thời gian hiện tại', null);
            const locVal = getStat('Thế giới.Địa điểm hiện tại', null);

            // 2. CẬP NHẬT VỊ TRÍ $4 (Thời gian)
            const elTime = document.getElementById('hud-time');
            if(elTime && timeVal) elTime.innerText = timeVal;

            // 3. CẬP NHẬT VỊ TRÍ $5 (Địa điểm)
            const elLoc = document.getElementById('hud-loc');
            if(elLoc && locVal) elLoc.innerText = locVal;

            // 4. ĐỔI MÀU (Dựa trên Thời gian thực tế + Thời tiết $6)
            const elBg = document.getElementById('hud-container');
            const elWeath = document.getElementById('hud-6');

            if(elBg) {
                const weatherText = elWeath ? elWeath.innerText : "";
                const currentTime = elTime ? elTime.innerText : "";
                // Gán vào data-color để CSS xử lý màu
                elBg.setAttribute('data-color', currentTime + " " + weatherText);
            }
        }

        render();
        if (typeof eventOn === 'function' && typeof Mvu !== 'undefined') {
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, render);
        }
    }

    if (typeof $ !== 'undefined' && typeof errorCatched !== 'undefined') {
        $(errorCatched(initHUD));
    } else {
        initHUD();
    }
</script>
</body>
</html>
