    background-position: center; background-repeat: no-repeat; background-size: contain;
    mix-blend-mode: plus-lighter;
    animation: nirvana-spin-slow 120s linear infinite;
    opacity: 0.2; 
}
.stage-5 .s5-bg { display: block; }
