/* Hiệu ứng xoay quanh Avatar ở GĐ5 */
.stage-5 .av-wrap::before { top: -10px; left: -10px; animation: nirvana-spin 8s linear infinite reverse; content: ''; position: absolute; width: 100%; height: 100%; border: 1px dashed rgba(255, 215, 0, 0.3); border-radius: 50%; }
.stage-5 .av-wrap::after { bottom: -10px; right: -10px; animation: nirvana-spin 8s linear infinite; content: ''; position: absolute; width: 100%; height: 100%; border: 1px dashed rgba(255, 215, 0, 0.3); border-radius: 50%; }

@keyframes nirvana-pulse { from { opacity: 0.6; box-shadow: 0 0 15px var(--s5-gold); } to { opacity: 1; box-shadow: 0 0 35px var(--s5-gold); } }
@keyframes nirvana-spin-slow { from { transform: translate(-50%, -50%) rotate(0deg); } to { transform: translate(-50%, -50%) rotate(360deg); } }
@keyframes nirvana-spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }

