const pickImg = (key, text) => {
    const list = IMG_DATA[key];
    if(!list) return '';
    const matches = list.filter(item => item.k && item.k.some(kw => text.includes(kw)));
    if(matches.length > 0) return matches[Math.floor(Math.random() * matches.length)].u;

    const eggStart = 9;
    const hasEggs = list.length > eggStart;
    const isEgg = hasEggs && Math.random() < 0.1;

    if(isEgg) {
        return list[Math.floor(Math.random() * (list.length - eggStart)) + eggStart].u;
    } else {
        return list[Math.floor(Math.random() * (hasEggs ? eggStart : list.length))].u;
    }
}

const pickImgStage = (key, gd) => {
    gd = parseInt(gd) || 0;
    let s = 1;
    if (gd > 75) s = 2;
    if (gd > 150) s = 3;
    if (gd > 225) s = 4;
    if (gd > 299) s = 5;

    const list = IMG_DATA[key];
    if (!list) return '';
    const stageImgs = list.filter(i => i.s === s);
    if (stageImgs.length > 0) return stageImgs[Math.floor(Math.random() * stageImgs.length)].u;

    const fallback = list.filter(i => !i.s);
    if (fallback.length > 0) return fallback[Math.floor(Math.random() * fallback.length)].u;

    return '';
}

const hexToRgb = (hex) => {
    let result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? `${parseInt(result[1], 16)}, ${parseInt(result[2], 16)}, ${parseInt(result[3], 16)}` : '255, 255, 255';
}

