            else imgUrl = pickImg(c.k, t1 + t2);
        }
        return {
            n: c.n,
            i: imgUrl,
            c: c.c,
            t: c.c,
            t1: t1,
            t2: t2,
            p1: POETS[i].p1,
            p2: POETS[i].p2,
            key: c.k,
            th: c.th,
            gd: gd,
