import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// Tính toán giai đoạn Giáng Tuyết
const tinhGiaiDoanGiangTuyet = (thienNghiep) => {
  if (thienNghiep >= 300) return 'Hoan Hỷ Thiên';
  if (thienNghiep >= 226) return 'Ngọc Sơn Khuynh Đảo';
  if (thienNghiep >= 151) return 'Hải Đường Xuân Túy';
  if (thienNghiep >= 76) return 'Vân Phá Nguyệt Khuy';
  return 'Dao Đài Băng Kính';
};

// Tính toán giai đoạn Trúc Yêu
const tinhGiaiDoanTrucYeu = (thienNghiep) => {
  if (thienNghiep >= 300) return 'Ma Hô La';
  if (thienNghiep >= 226) return 'Ba Xà Thôn Tượng';
  if (thienNghiep >= 151) return 'Tham Hoan Cầu Sách';
  if (thienNghiep >= 76) return 'Sạ Noãn Hoàn Hàn';
  return 'Linh Khiếu Vị Khai';
};

export const Schema = z.object({
  'Thế giới': z.object({
    'Thời gian hiện tại': z.string().prefault('Chờ khởi tạo'),
    'Địa điểm hiện tại': z.string().prefault('Chờ khởi tạo'),
  }),

  'Giáng Tuyết': z
    .object({
      'Thiện nghiệp': z.coerce.number().transform(v => _.clamp(v, 0, 300)).prefault(0),
      'Giai đoạn': z.string().prefault('Dao Đài Băng Kính'),
      'Tự bạch': z.string().prefault(''),
      'Y phục': z.string().prefault('Chưa cập nhật'),
      'Ngoại hình': z.string().prefault('Chưa cập nhật'),
    })
    .transform(data => {
      data['Giai đoạn'] = tinhGiaiDoanGiangTuyet(data['Thiện nghiệp']);
      return data;
    }),

  'Trúc Yêu': z
    .object({
      'Thiện nghiệp': z.coerce.number().transform(v => _.clamp(v, 0, 300)).prefault(0),
      'Giai đoạn': z.string().prefault('Linh Khiếu Vị Khai'),
      'Tự bạch': z.string().prefault(''),
      'Y phục': z.string().prefault('Chưa cập nhật'),
      'Ngoại hình': z.string().prefault('Chưa cập nhật'),
    })
    .transform(data => {
      data['Giai đoạn'] = tinhGiaiDoanTrucYeu(data['Thiện nghiệp']);
      return data;
    }),

  'Mạnh Thu Nương': z.object({
    'Y phục': z.string().prefault('Chưa cập nhật'),
    'Ngoại hình': z.string().prefault('Chưa cập nhật'),
  }),

  'Từ Chi Phật Mẫu': z.object({
    'Y phục': z.string().prefault('Chưa cập nhật'),
    'Ngoại hình': z.string().prefault('Chưa cập nhật'),
  }),
});

$(() => {
  registerMvuSchema(Schema);
});
